  ('bookkeeper-moex-01059', 'bookkeeper', 'bookkeeper-moex-106-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計法之規定，下列敘述何者正確？ 商業不得視實際需要增減會計項目 財務報表之附註，不應視為財務報表之一部分 商業得於財務報表附註編製重要會計項目明細表 重大或有負債不需在財務報表附註中揭露', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "c473f73014d0", "answer_pdf_sha1": "8e580acee728", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
